1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface QuoteStep {
6	  op: "quote";
7	  items: Array<Record<string, unknown>>;
8	}
9	
10	export interface ClaimStep {
11	  op: "claim";
12	  policy: number;
13	  incident: {
14	    cause: string;
15	    damages: Array<{ itemType: string; amount: number }>;
16	  };
17	}
18	
19	export type Step = QuoteStep | ClaimStep;
20	
21	export interface Scenario {
22	  customer: Customer;
23	  steps: Step[];
24	}
25	
26	export type StepResult =
27	  | { premium: number }
28	  | { payout: number; remainingCap: number };
29	
30	export interface ScenarioResult {
31	  results: StepResult[];
32	}
33	
34	const PROCESSING_FEE = 5;
35	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
36	
37	const BASE_PREMIUM: Record<string, number> = {
38	  sword: 100,
39	  amulet: 60,
40	  staff: 80,
41	  potion: 40,
42	  rune: 25,
43	};
44	
45	const basePremiumFor = (item: Record<string, unknown>): number =>
46	  BASE_PREMIUM[item.type as string] ?? 0;
47	
48	const quotePremium = (step: QuoteStep): StepResult => {
49	  const baseTotal = step.items.reduce(
50	    (sum, item) => sum + basePremiumFor(item),
51	    0,
52	  );
53	  const firstInsuranceSurcharge = baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
54	  return { premium: baseTotal + firstInsuranceSurcharge + PROCESSING_FEE };
55	};
56	
57	const processStep = (step: Step): StepResult => {
58	  if (step.op === "quote") return quotePremium(step);
59	  return { payout: 0, remainingCap: 0 };
60	};
61	
62	export const runScenario = (scenario: Scenario): ScenarioResult => ({
63	  results: scenario.steps.map(processStep),
64	});
